// Parse Groq response and extract activities
const response = $input.item.json.response;
let parsed;

try {
  // Extract JSON from markdown code blocks if present
  const jsonMatch = response.match(/```json\s*([\s\S]*?)\s*```/) || response.match(/\{[\s\S]*\}/);
  const jsonStr = jsonMatch ? jsonMatch[1] || jsonMatch[0] : response;
  parsed = JSON.parse(jsonStr);
} catch (error) {
  console.error('Failed to parse Groq response:', error);
  return [];
}

// If no news found, return empty array
if (parsed.no_news || !parsed.activities || parsed.activities.length === 0) {
  return [];
}

// Generate content hash for deduplication (SHA-256 of title + source_url)
const crypto = require('crypto');

const activities = parsed.activities.map(activity => ({
  competitor_name: $input.item.json.competitor_name,
  alert_type: activity.alert_type,
  title: activity.title,
  summary: activity.summary,
  full_content: activity.full_content || activity.summary,
  source_url: activity.source_url,
  source_domain: activity.source_domain,
  published_at: activity.published_at,
  sentiment: activity.sentiment || 'neutral',
  priority: activity.priority || 'medium',
  content_hash: crypto.createHash('sha256').update(activity.title + activity.source_url).digest('hex'),
  reasoning: activity.reasoning
}));

return activities.map(activity => ({ json: activity }));

// Log successful alert creation
console.log(`[SUCCESS] Alert created for ${$json.competitor_name}: ${$json.title}`);
return $input.all();

// Log errors or duplicates
if ($json.deduplicated) {
  console.log(`[DUPLICATE] Skipped duplicate alert for ${$input.item.json.competitor_name}: ${$input.item.json.title}`);
} else {
  console.error(`[ERROR] Failed to create alert for ${$input.item.json.competitor_name}:`, $json.error);
}
return $input.all();
